// One item per calendar day (brief is per-day, shared across platforms).
const cal = $('Get Calendar Days').first().json.data;
const wh = $('Webhook').first().json.body;
const businessId = wh.business_id;
const calendarId = wh.calendar_id;

return cal.days.map(day => {
  // synthetic slot_id for the brief (one brief per day, not per platform)
  const brief_slot_id = `${calendarId}_${day.date}_brief`;
  return { json: {
    calendar_id: calendarId,
    business_id: businessId,
    day: day,
    briefPayload: { slot_id: brief_slot_id, business_id: businessId, day: day }
  }};
});

// Fan out: for each day × each platform, build a slot item.
// brief responses are $input.all() (N items, one per day).
const briefs = $input.all();
const dayJobs = $('Prepare Day Jobs').all();
const wh = $('Webhook').first().json.body;

// Accept either platforms[] or single platform; default instagram
let platforms = wh.platforms;
if (!Array.isArray(platforms) || platforms.length === 0) {
  platforms = wh.platform ? [wh.platform] : ['instagram'];
}
platforms = platforms.map(p => String(p).toLowerCase());

const allowed = ['instagram', 'facebook', 'linkedin', 'twitter'];
for (const p of platforms) {
  if (!allowed.includes(p)) {
    throw new Error('Unsupported platform: ' + p + '. Allowed: ' + allowed.join(', '));
  }
}

const slots = [];
briefs.forEach((b, i) => {
  const dayJob = dayJobs[i].json;
  const brief = b.json.brief;
  platforms.forEach(platform => {
    const slot_id = `${dayJob.calendar_id}_${dayJob.day.date}_${platform}`;
    slots.push({ json: {
      calendar_id: dayJob.calendar_id,
      business_id: dayJob.business_id,
      slot_id: slot_id,
      date: dayJob.day.date,
      theme: dayJob.day.theme,
      objective: dayJob.day.objective,
      platform: platform,
      brief: brief,
      captionPayload: { slot_id, business_id: dayJob.business_id, platform, brief }
  }});
  });
});
return slots;

// Pair caption responses with slot context by index. Build assetPayload.
const caps = $input.all();
const slots = $('Build Slot Matrix').all();
const wh = $('Webhook').first().json.body;
const genImg = wh.generate_images === true;

return caps.map((c, i) => {
  const s = slots[i].json;
  return { json: {
    calendar_id: s.calendar_id,
    business_id: s.business_id,
    slot_id: s.slot_id,
    date: s.date,
    theme: s.theme,
    objective: s.objective,
    platform: s.platform,
    brief: s.brief,
    caption: c.json.caption,
    hashtags: c.json.hashtags,
    char_count: c.json.char_count,
    generate_images: genImg,
    assetPayload: { slot_id: s.slot_id, business_id: s.business_id, platform: s.platform, theme: s.theme, brief: s.brief }
  }};
});

// Pair asset responses with records by index (true branch).
const assets = $input.all();
const recs = $('Assemble Records').all();

return assets.map((a, i) => {
  const r = recs[i].json;
  return { json: {
    ...r,
    image_status: 'generated',
    image_prompt: a.json.image_prompt || null,
    image_url: a.json.image_url || null,
    image_returned_as: a.json.image_returned_as || null
  }};
});

// Items arrive from whichever branch ran. Group by date for a client-friendly summary.
const recs = $input.all();
const wh = $('Webhook').first().json.body;

const items = recs.map(r => ({
  date: r.json.date,
  theme: r.json.theme,
  slot_id: r.json.slot_id,
  platform: r.json.platform,
  caption: r.json.caption,
  hashtags: r.json.hashtags,
  char_count: r.json.char_count,
  image_status: r.json.image_status,
  image_prompt: r.json.image_prompt || null
}));

// Group by date for nicer demo output
const byDate = {};
items.forEach(it => {
  if (!byDate[it.date]) byDate[it.date] = { date: it.date, theme: it.theme, platforms: [] };
  byDate[it.date].platforms.push({
    platform: it.platform,
    char_count: it.char_count,
    hashtag_count: (it.hashtags || []).length,
    image_status: it.image_status
  });
});
const days_summary = Object.values(byDate);

// Determine platforms used
let platforms = wh.platforms;
if (!Array.isArray(platforms) || platforms.length === 0) {
  platforms = wh.platform ? [wh.platform] : ['instagram'];
}

return [{ json: {
  success: true,
  calendar_id: wh.calendar_id,
  platforms: platforms.map(p => String(p).toLowerCase()),
  generate_images: wh.generate_images === true,
  days_count: days_summary.length,
  slots_count: items.length,
  days_summary,
  items
}}];
